# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import urllib.request
import urllib.error
import base64

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    headers = request['headers']

    enrich_urls_header = headers.get('x-enrich-url')
    
    enrichment_results = []

    if enrich_urls_header:
        enrich_urls_str = enrich_urls_header[0]['value']
        enrich_urls = [url.strip() for url in enrich_urls_str.split(',') if url.strip()]

        for url in enrich_urls:
            try:
                with urllib.request.urlopen(url, timeout=2) as response:
                    status_code = response.getcode()
                    response_body = response.read().decode('utf-8', errors='ignore')
                    
                    encoded_data = base64.b64encode(response_body.encode('utf-8')).decode('utf-8')

                    enrichment_results.append({
                        'url': url,
                        'status': status_code,
                        'data': encoded_data
                    })
            except urllib.error.HTTPError as e:
                enrichment_results.append({
                    'url': url,
                    'status': e.code,
                    'error': str(e)
                })
            except urllib.error.URLError as e:
                enrichment_results.append({
                    'url': url,
                    'status': None,
                    'error': str(e.reason)
                })
            except Exception as e:
                enrichment_results.append({
                    'url': url,
                    'status': None,
                    'error': f"An unexpected error occurred: {str(e)}"
                })

    if enrichment_results:
        json_results_str = json.dumps(enrichment_results)
        encoded_json_results = base64.b64encode(json_results_str.encode('utf-8')).decode('utf-8')

        headers['x-enrichment-data'] = [{
            'key': 'X-Enrichment-Data',
            'value': encoded_json_results
        }]

    return request